def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    epsilon = 1e-9
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (cap + epsilon)
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        factor = 1.0
        complexity = 1.0
        modulation = 1.0
        side_effect = 0.0
        dynamic_penalty = 0.0
        boundary_adjustment = 1.0
        for a in range(1, 15):
            if a % 2 == 0:
                factor *= 1.03 + 0.005 * a
            else:
                factor *= 0.97 - 0.004 * a
            if ratio < 0.07 * a:
                base_score += (a**3) / (1 + np.exp(-ratio * a)) * factor
            else:
                base_score += (np.sqrt(a*a + 1) + ratio**2.5) * factor / (a + 1)
            if ((cap * a) + (a**2)) % 8 == 0:
                base_score *= 1.06
            elif ((cap + a) * 3) % 9 == 0:
                base_score *= 0.94
            if a == 7:
                for b in range(1, 7):
                    delta = cap - item * (b**3)
                    if delta > 0:
                        if delta % (b+3) == 0:
                            dynamic_penalty += np.log1p(delta)/(b+2)
                        else:
                            dynamic_penalty -= np.sqrt(abs(delta))/(b+4)
                    else:
                        dynamic_penalty -= abs(delta)**1.25/(b+6)
            if ratio > 0.8 and a % 3 == 0:
                modulation *= 1.12 + 0.015 * a
            elif ratio < 0.15 and a % 4 == 1:
                modulation *= 0.88 - 0.02 * a
            if a % 5 == 2 and cap % (a+2) == 0:
                side_effect += np.cos(a * ratio * 2) * 0.6
            elif a % 6 == 3 and cap % (a+3) == 0:
                side_effect -= np.sin(a * ratio) * 0.4
            if a % 7 == 0:
                boundary_adjustment *= 1 + 0.01 * np.tanh(ratio * a)
        base_score += (dynamic_penalty + side_effect) * 0.85
        base_score *= modulation * boundary_adjustment
        if base_score < 0:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.sqrt(cap) * 1.2)
        else:
            if cap > item * 3.5:
                priorities[i] = -base_score / (np.sqrt(cap) + 0.8) * (1 + ratio**1.2)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**2.3)
        if ratio > 0.9:
            priorities[i] *= 1.18
        elif ratio < 0.04:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 3 == 1:
            priorities[i] *= 1.03
        if (cap + item) % 5 == 0:
            priorities[i] *= np.log1p(abs(priorities[i]) + 1)
        else:
            priorities[i] /= 1 + np.exp(-ratio * cap / (item + epsilon))
    return priorities
